CREATE TABLE IF NOT EXISTS ai_organizational_memory (id BIGSERIAL PRIMARY KEY, workspace_id UUID NOT NULL REFERENCES workspaces(id) ON DELETE CASCADE, memory_payload JSONB NOT NULL DEFAULT '{}'::jsonb, memory_only BOOLEAN NOT NULL DEFAULT true, recommendation_only BOOLEAN NOT NULL DEFAULT true, requires_human_review BOOLEAN NOT NULL DEFAULT true, no_autonomous_execution BOOLEAN NOT NULL DEFAULT true, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW());
